data.adding-a-new-station-type#Adding a New S:
To add a new station type:
Add a new key to the stationTypes table with a unique identifier
Define all required properties (placeItem, size, sceneObjects, categories, recipes)
Create the corresponding inventory items (see Items Setup)
Optionally add upgrade items and stash sizes for upgradable stations
["cooking"] = {
    placeItem = 'cooking_station',
    size = vec3(1.5, 1.5, 1.5),
    stashSizes = {
        [1] = { weight = 10000, slots = 5 },
    },
    sceneObjects = {
        [1] = {
            {
                model = `prop_bbq_2`,
                pos = vec3(0, 0, 0.0),
                rot = vec3(0, 0, 0),
                interactOffset = vec3(0, 0, 1),
                previewOffsets = {
                    pos = vec3(0, 0, 1),
                    rot = vec3(0, 0, 0)
                },
                camSettings = {
                    posOffset = vec3(1, 0, 1),
                    viewOffset = vec3(0, 0, 0.5),
                    fov = 60
                }
            },
        },
    },
    categories = {
        {
            id = "food",
            label = "Food",
            icon = "utensils"
        },
    },
    recipes = {
        [1] = {
            {
                name = "burger",
                label = "Burger",
                category = "food",
                description = "A delicious grilled burger.",
